// Control inteligente: horario + cuota semanal + aleatorización
const https = require('https');

function httpsGet(targetUrl, headers) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const opts = { hostname: parsed.hostname, path: parsed.pathname + parsed.search, headers };
    https.get(opts, res => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { resolve([]); }
      });
    }).on('error', () => resolve([]));
  });
}

const config = $input.first().json;
const now = new Date();
const madridTime = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
const hour = madridTime.getHours();
const day = madridTime.getDay();

if (hour < 8 || hour >= 22 || day === 0) return [];

function seededRandom(seed) {
  const x = Math.sin(seed * 9999) * 10000;
  return x - Math.floor(x);
}
const oneJan = new Date(madridTime.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((madridTime - oneJan) / 86400000 + oneJan.getDay() + 1) / 7);
const weekSeed = madridTime.getFullYear() * 100 + weekNumber;
const minWeek = config.MAX_PROPOSALS_WEEK_MIN || 50;
const maxWeek = config.MAX_PROPOSALS_WEEK_MAX || 60;
const weeklyTarget = Math.floor(minWeek + seededRandom(weekSeed) * (maxWeek - minWeek + 1));

const dayOfWeek = day === 0 ? 7 : day;
const madridDateStr = madridTime.toISOString().split('T')[0];
const mondayDate = new Date(madridDateStr + 'T00:00:00');
mondayDate.setDate(mondayDate.getDate() - (dayOfWeek - 1));
const mondayStr = mondayDate.toISOString().split('T')[0];
const refDate = new Date(mondayStr + 'T12:00:00Z');
const madridRef = new Date(refDate.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
const utcRef = new Date(refDate.toLocaleString('en-US', { timeZone: 'UTC' }));
const madridOffsetMs = madridRef - utcRef;
const mondayMidnightUTC = new Date(new Date(mondayStr + 'T00:00:00').getTime() - madridOffsetMs);
const startISO = mondayMidnightUTC.toISOString();

let proposalsThisWeek = 0;
try {
  const proposals = await httpsGet(
    `${config.SUPABASE_URL}/rest/v1/workana_proposals?select=id&created_at=gte.${startISO}`,
    { 'apikey': config.SUPABASE_KEY, 'Authorization': `Bearer ${config.SUPABASE_KEY}` }
  );
  proposalsThisWeek = Array.isArray(proposals) ? proposals.length : 0;
} catch (error) {
  console.error('Error consultando cuota:', error.message);
}

const remaining = weeklyTarget - proposalsThisWeek;
if (remaining <= 0) {
  console.log(`Cuota alcanzada: ${proposalsThisWeek}/${weeklyTarget}`);
  return [];
}

const daysLeftAfterToday = 6 - dayOfWeek;
const hoursLeftToday = Math.max(0, 22 - hour);
const totalHoursLeft = (daysLeftAfterToday * 14) + hoursLeftToday;
const executionsLeft = Math.max(1, totalHoursLeft * 2);
const probability = Math.min(0.95, remaining / executionsLeft);

let hasFreshProjects = false;
try {
  const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString();
  const fresh = await httpsGet(
    `${config.SUPABASE_URL}/rest/v1/workana_projects?select=id&status=eq.new&created_at=gte.${twoHoursAgo}&proposals_count=lt.10&limit=1`,
    { 'apikey': config.SUPABASE_KEY, 'Authorization': `Bearer ${config.SUPABASE_KEY}` }
  );
  hasFreshProjects = Array.isArray(fresh) && fresh.length > 0;
} catch (e) { /* no bloquear */ }

const roll = Math.random();
if (roll > probability && !hasFreshProjects) {
  console.log(`Skip aleatorio (prob: ${(probability * 100).toFixed(1)}%, enviadas: ${proposalsThisWeek}/${weeklyTarget})`);
  return [];
}

console.log(`Ejecutando (prob: ${(probability * 100).toFixed(1)}%, enviadas: ${proposalsThisWeek}/${weeklyTarget})`);

return [{
  json: {
    ...config,
    current_hour: hour,
    current_day: day,
    proposals_this_week: proposalsThisWeek,
    weekly_target: weeklyTarget,
    remaining_this_week: remaining,
    timestamp: now.toISOString()
  }
}];

// Extraer proyectos del resultado del scraping
const data = $input.first().json;

if (!data.success || !data.projects || data.projects.length === 0) {
  console.log('No se encontraron proyectos o error en scraping');
  return [];
}

// Devolver cada proyecto como item individual con config
// Deduplicar por URL (mismo proyecto puede aparecer en múltiples categorías)
const seen = new Set();
const unique = data.projects.filter(p => {
  if (!p.url || seen.has(p.url)) return false;
  seen.add(p.url);
  return true;
});
console.log(`Proyectos: ${data.projects.length} total, ${unique.length} únicos (dedup)`);

return unique.map(project => ({
  json: {
    ...project,
    config: {
      PUPPETEER_URL: $('CONFIG').item.json.PUPPETEER_URL,
      SUPABASE_URL: $('CONFIG').item.json.SUPABASE_URL,
