      MIN_RELEVANCE_AUTO: parseInt($('CONFIG').item.json.MIN_RELEVANCE_AUTO),
      MAX_PROPOSALS_ON_PROJECT: parseInt($('CONFIG').item.json.MAX_PROPOSALS_ON_PROJECT),
    }
  }
}));

// Filtrar proyectos nuevos - consulta Supabase para deduplicar
const https = require('https');

function httpsGet(targetUrl, headers) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const opts = { hostname: parsed.hostname, path: parsed.pathname + parsed.search, headers };
    https.get(opts, res => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) return reject(new Error('HTTP ' + res.statusCode + ': ' + body.substring(0, 300)));
        try { resolve(JSON.parse(body)); } catch (e) { reject(new Error('JSON parse error: ' + body.substring(0, 300))); }
      });
    }).on('error', reject);
  });
}

const items = $input.all();
if (items.length === 0) return [];

const config = items[0].json.config;
if (!config || !config.SUPABASE_URL) throw new Error('CONFIG sin SUPABASE_URL');

const scraped = items.map(i => i.json.url).filter(Boolean);
if (scraped.length === 0) throw new Error('Items sin campo url: ' + Object.keys(items[0].json).join(','));

const existingUrls = new Set();
const batchSize = 50;
for (let i = 0; i < scraped.length; i += batchSize) {
  const batch = scraped.slice(i, i + batchSize);
  const urlFilter = batch.map(u => '"' + u + '"').join(',');
  const queryUrl = config.SUPABASE_URL + '/rest/v1/workana_projects?select=workana_url&workana_url=in.(' + urlFilter + ')';
  const existing = await httpsGet(queryUrl, {
    'apikey': config.SUPABASE_KEY,
    'Authorization': 'Bearer ' + config.SUPABASE_KEY,
  });
  if (Array.isArray(existing)) existing.forEach(r => existingUrls.add(r.workana_url));
}

const seen = new Set();
const newItems = items.filter(item => {
  const url = item.json.url;
  if (!url || existingUrls.has(url) || seen.has(url)) return false;
  seen.add(url);
  return true;
});

if (newItems.length === 0) {
  return [{ json: { _debug: true, message: 'Los ' + items.length + ' proyectos ya existen en Supabase (' + existingUrls.size + ' en DB). No hay nuevos.', total: items.length, existentes: existingUrls.size } }];
}

return newItems;

// Obtener detalles del proyecto via Puppeteer y combinar con datos del scraping
const https = require('https');
const http = require('http');

function httpGet(targetUrl) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const lib = parsed.protocol === 'https:' ? https : http;
    lib.get({ hostname: parsed.hostname, port: parsed.port, path: parsed.pathname + parsed.search }, res => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { reject(new Error('JSON parse: ' + body.substring(0, 300))); }
      });
    }).on('error', reject);
  });
}

const basic = $input.first().json;

if (basic._debug) return [];

const config = basic.config;

console.log(`[Obtener Detalles] Procesando: ${basic.title}`);

let detailsResponse;
try {
  detailsResponse = await httpGet(`${config.PUPPETEER_URL}/project-details?url=${encodeURIComponent(basic.url)}`);
} catch (error) {
  console.log(`[Obtener Detalles] Error: ${error.message}`);
  detailsResponse = { success: false, error: error.message };
}

if (!detailsResponse.success) {
  console.log(`[Obtener Detalles] Error detalles: ${detailsResponse.error} → continuando con datos básicos`);
  // Continuar con datos básicos en vez de parar
  return [{ json: { ...basic, details_error: true } }];
}

const details = detailsResponse.details;

// 2. Parsear presupuesto de texto a números
function parseBudget(text) {
  if (!text) return { min: null, max: null, currency: 'USD', type: 'open' };
  const t = text.replace(/\s+/g, ' ').trim();
  let currency = 'USD';
  if (/EUR|€/i.test(t)) currency = 'EUR';
  if (/hora|hour|hr/i.test(t)) {
    const match = t.match(/(\d+[\.,]?\d*)/);
    const val = match ? parseFloat(match[1].replace(',', '.')) : null;
    return { min: val, max: val, currency, type: 'hourly' };
  }
  const rangeMatch = t.match(/(\d+[\.,]?\d*)\s*[-–a]\s*(\d+[\.,]?\d*)/);
  if (rangeMatch) {
    return { min: parseFloat(rangeMatch[1].replace(',', '.')), max: parseFloat(rangeMatch[2].replace(',', '.')), currency, type: 'fixed' };
  }
  const singleMatch = t.match(/(\d+[\.,]?\d*)/);
  if (singleMatch) {
    const val = parseFloat(singleMatch[1].replace(',', '.'));
    return { min: val, max: val, currency, type: 'fixed' };
  }
  return { min: null, max: null, currency, type: 'open' };
}

// 3. Extraer número de propuestas
const proposalsText = details.proposals || basic.proposals_text || '';
const proposalsMatch = proposalsText.match(/(\d+)/);
const proposalsCount = proposalsMatch ? parseInt(proposalsMatch[1]) : 0;

// 4. Filtrar por número de propuestas
const maxProposals = parseInt(config.MAX_PROPOSALS_ON_PROJECT) || 50;
if (proposalsCount > maxProposals) {
  console.log(`[Obtener Detalles] ⛔ Demasiadas propuestas (${proposalsCount}>${maxProposals}): ${basic.title}`);
  return [];
}

const budgetParsed = parseBudget(details.budget || basic.budget_text);

console.log(`[Obtener Detalles] ✅ ${basic.title} | Props: ${proposalsCount} | Budget: ${budgetParsed.min}-${budgetParsed.max} ${budgetParsed.currency}`);

return [{
  json: {
    ...basic,
    full_description: details.description || basic.description,
    full_title: details.title || basic.title,
    budget_detail: details.budget || basic.budget_text,
    budget_min: budgetParsed.min,
    budget_max: budgetParsed.max,
    budget_currency: budgetParsed.currency,
    budget_type: budgetParsed.type,
    category: details.category || basic.category || '',
    deadline: details.deadline || '',
    skills_detail: details.skills && details.skills.length > 0 ? details.skills : basic.skills,
    proposals_count: proposalsCount,
    client_name: details.client?.name || '',
    client_country: details.client?.country || '',
    client_rating: details.client?.rating || '',
    client_verified: details.client?.verified || false,
    client_projects_posted: details.client?.projects_posted || null,
    client_hire_rate: details.client?.hire_rate || null,
    publish_date: details.publish_date || basic.date_text || '',
    full_text: details.full_text || '',
  }
}];

// Obtener stats de conversión históricas (v2) para enriquecer el prompt
const https = require('https');

function httpsGet(targetUrl, headers) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const opts = { hostname: parsed.hostname, path: parsed.pathname + parsed.search, headers };
    https.get(opts, res => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { resolve([]); }
      });
    }).on('error', () => resolve([]));
  });
}

const cfg = $input.first().json.config;
let conversionStats = '';
try {
  const stats = await httpsGet(
    `${cfg.SUPABASE_URL}/rest/v1/workana_conversion_stats_v2`,
    { 'apikey': cfg.SUPABASE_KEY, 'Authorization': `Bearer ${cfg.SUPABASE_KEY}` }
  );
  if (Array.isArray(stats) && stats.length > 0) {
    conversionStats = '\n## DATOS DE CONVERSIÓN HISTÓRICOS (v2):\n' +
      stats.map(s => `- ${s.category}: ${s.response_rate_pct || 0}% tasa respuesta, ${s.win_rate_pct || 0}% win rate (${s.total_sent} enviadas, ${s.total_won || 0} ganadas)`).join('\n') +
      '\nUsa estos datos para ajustar tu enfoque y tono según la categoría.';
  }
} catch (e) { /* no bloquear si la vista no existe aún */ }

// Obtener patrones ganadores de propuestas exitosas
let winningPatterns = '';
try {
  const patterns = await httpsGet(
    `${cfg.SUPABASE_URL}/rest/v1/workana_winning_patterns?limit=5`,
    { 'apikey': cfg.SUPABASE_KEY, 'Authorization': `Bearer ${cfg.SUPABASE_KEY}` }
  );
  if (Array.isArray(patterns) && patterns.length > 0) {
    winningPatterns = '\n## PATRONES DE PROPUESTAS GANADORAS:\n' +
      patterns.map(p => `- Categoría: ${p.category || '?'} | Gancho: "${(p.opening_hook || '').substring(0, 80)}..." | Largo: ${p.word_count || '?'} palabras | Tono: ${p.tone || '?'}`).join('\n') +
      '\nImita estos patrones en tu propuesta.';
  }
} catch (e) { /* no bloquear */ }

// Construir body para OpenAI - Selección focalizada + precio justo con Claude Code
const d = $input.first().json;

// --- Client Profiling ---
let clientProfile = 'desconocido';
const rating = parseFloat(d.client_rating) || 0;
const verified = d.client_verified === true;
const projectsPosted = parseInt(d.client_projects_posted) || 0;
const hireRate = parseFloat(d.client_hire_rate) || 0;

if (projectsPosted >= 10 && hireRate >= 70 && rating >= 4.5) {
  clientProfile = 'premium';
} else if (projectsPosted >= 3 && rating >= 4.0) {
  clientProfile = 'experimentado';
} else if (projectsPosted >= 1) {
  clientProfile = 'intermedio';
} else {
  clientProfile = 'nuevo';
}

let clientProfileInstructions = '';
if (clientProfile === 'premium') {
  clientProfileInstructions = '\n## PERFIL CLIENTE: PREMIUM\n- Este cliente tiene historial comprobado y alta tasa de contratación.\n- Usa tono profesional y directo, enfatiza calidad y resultados.\n- Menciona escalabilidad y mantenimiento a largo plazo.\n- Puede pagar precios más altos - no subas el precio, pero enfatiza valor.';
} else if (clientProfile === 'experimentado') {
  clientProfileInstructions = '\n## PERFIL CLIENTE: EXPERIMENTADO\n- Cliente con experiencia en Workana, sabe lo que busca.\n- Sé específico técnicamente, evita explicaciones básicas.\n- Enfatiza diferenciación: qué te hace mejor que los otros 10+ freelancers.';
} else if (clientProfile === 'intermedio') {
  clientProfileInstructions = '\n## PERFIL CLIENTE: INTERMEDIO\n- Cliente con algo de experiencia, puede necesitar guía.\n- Equilibra tecnicismos con explicaciones de beneficio.\n- Transmite confianza y proceso claro.';
} else {
  clientProfileInstructions = '\n## PERFIL CLIENTE: NUEVO EN WORKANA\n- Primera(s) vez contratando, puede estar inseguro.\n- Transmite máxima confianza y proceso claro paso a paso.\n- Enfatiza garantías: comunicación constante, entregas parciales, satisfacción.\n- Evita jerga técnica excesiva.';
}

// --- A/B Testing ---
// Asignar variante A o B basada en hash del URL del proyecto
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash);
}
const projectHash = simpleHash(d.url || d.title || '');
const abVariant = projectHash % 2 === 0 ? 'A' : 'B';

let abTestInstructions = '';
if (abVariant === 'A') {
  abTestInstructions = '\n## VARIANTE A: GANCHO TÉCNICO\n- Abre con una observación técnica específica sobre su proyecto.\n- Demuestra que ya analizaste su problema antes de escribir.\n- Ejemplo: "El flujo de datos que describes tiene un cuello de botella clásico en..."';
} else {
  abTestInstructions = '\n## VARIANTE B: GANCHO RESULTADO\n- Abre con un resultado concreto que lograste en un proyecto similar.\n- Conecta ese resultado con lo que el cliente necesita.\n- Ejemplo: "En un proyecto similar redujimos el tiempo de procesamiento un 70%..."';
}

// --- Dynamic Pricing ---
let dynamicPricing = '';
if (d.budget_min && d.budget_max && d.budget_type !== 'open') {
  const clientMid = (d.budget_min + d.budget_max) / 2;
  if (d.budget_currency === 'EUR' || d.budget_currency === 'USD') {
    dynamicPricing = `\n## CONTEXTO DE PRECIO DEL CLIENTE:\n- El cliente indica un rango de ${d.budget_min}-${d.budget_max} ${d.budget_currency} (tipo: ${d.budget_type}).\n- Punto medio del cliente: ${clientMid} ${d.budget_currency}.\n- RECUERDA: Ignora este rango y pon TU precio justo. Pero si tu precio justo está dentro o cerca de su rango, menciona en internal_notes que hay alineación de presupuesto.`;
  }
}

const systemPrompt = `Eres un generador experto de propuestas para Workana. Debes responder SIEMPRE en JSON con esta estructura exacta:
{
  "relevance_score": 0-100,
  "red_flags": ["flag1", "flag2"],
  "should_apply": true/false,
  "proposal_text": "texto de la propuesta listo para copiar",
  "questions_text": "preguntas para el cliente (1-2 máximo)",
  "budget_suggested": número en EUR,
  "delivery_days": número,
  "skills_recommended": ["skill1", "skill2"],
  "portfolio_items": ["item1", "item2"],
  "tone": "direct|warm|technical|urgent",
  "internal_notes": {
    "perfil_detectado": "técnico/negocio/novato + formal/casual/urgente + precio/calidad/rapidez",
    "dolor_real": "descripción",
    "por_que_yo": "razón específica",
    "tiempo_estimado": "rango",
    "razonamiento_precio": "cómo llegaste al precio",
    "client_profile": "premium/experimentado/intermedio/nuevo",
    "ab_variant": "A o B",
    "budget_alignment": "descripción de alineación con presupuesto del cliente"
  }
}

IMPORTANTE: El campo 'proposal_text' debe ser la propuesta COMPLETA lista para enviar, incluyendo preguntas al final si las hay.
El campo 'tone' indica el tono dominante que usaste: direct (directo al grano), warm (cálido cercano), technical (técnico experto), urgent (urgencia y velocidad).`;

// Detectar categoría y seleccionar template de énfasis
const allText = ((d.category || '') + ' ' + (d.full_title || d.title || '') + ' ' + (d.full_description || d.description || '')).toLowerCase();

let categoryEmphasis = '';

if (/inteligencia artificial|machine learning|\bai\b|\bml\b|chatbot|nlp|gpt|openai|claude|rag|agente.*ia/i.test(allText)) {
  categoryEmphasis = `
## ÉNFASIS PARA PROYECTO DE IA:
- Destaca ROI concreto (X% mejora en eficiencia, Y horas ahorradas)
- Menciona casos de uso específicos implementados
- Vocabulario técnico de IA pero explica beneficios de negocio
- Enfatiza: modelo correcto para el caso, escalabilidad, integración
- Portfolio prioritario: RAG, Asistente Virtual, Voice Bot`;
} else if (/web|landing|wordpress|e-commerce|ecommerce|tienda|woocommerce|shopify|pagina|sitio|blog|portafolio/i.test(allText)) {
  categoryEmphasis = `
## ÉNFASIS PARA PROYECTO WEB:
- Destaca velocidad de entrega (Claude Code permite entregar más rápido)
- Menciona responsive, SEO, performance (Core Web Vitals)
- Énfasis en diseño moderno y conversión (funcional, no solo bonito)
- Si es e-commerce: integraciones de pago, inventario, analytics
- Portfolio prioritario: Sistema Logística E-commerce`;
} else if (/automatizaci[oó]n|automation|n8n|make|zapier|bot|whatsapp|telegram|scraper|scraping/i.test(allText)) {
  categoryEmphasis = `
## ÉNFASIS PARA PROYECTO DE AUTOMATIZACIÓN:
