const https = require('https');

function httpsPost(targetUrl, headers, bodyObj) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const data = JSON.stringify(bodyObj);
    const opts = { hostname: parsed.hostname, path: parsed.pathname + parsed.search, method: 'POST', headers: { ...headers, 'Content-Length': Buffer.byteLength(data) } };
    const req = https.request(opts, res => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => resolve(body));
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

