let score = 30;

// Factor 1: Frescura (hasta +25)
const publishDate = (d.publish_date || '').toLowerCase();
const minsMatch = publishDate.match(/(\d+)\s*(minuto|minute|min)/i);
const hoursMatch = publishDate.match(/(\d+)\s*(hora|hour)/i);
if (minsMatch || publishDate.includes('momento') || publishDate.includes('just')) {
  score += 25;
} else if (hoursMatch) {
  const hours = parseInt(hoursMatch[1]);
  if (hours <= 1) score += 22;
  else if (hours <= 3) score += 18;
  else if (hours <= 6) score += 12;
  else if (hours <= 12) score += 6;
}

// Factor 2: Competencia baja (hasta +20)
const proposals = d.proposals_count || 0;
if (proposals <= 3) score += 20;
else if (proposals <= 7) score += 15;
else if (proposals <= 15) score += 10;
else if (proposals <= 25) score += 3;

// Factor 3: Cliente verificado (+8)
if (d.client_verified === true) score += 8;

// Factor 4: Rating alto (hasta +8)
const rating = parseFloat(d.client_rating) || 0;
if (rating >= 4.8) score += 8;
else if (rating >= 4.5) score += 6;
else if (rating >= 4.0) score += 3;

// Factor 5: Presupuesto definido (+5)
const budget = (d.budget_detail || d.budget_text || '').toLowerCase();
if (budget && !budget.includes('a definir') && !budget.includes('open') && !budget.includes('abierto')) {
  score += 5;
}

// Factor 6: Cliente con historial de contratación (hasta +7)
const hireRate = parseFloat(d.client_hire_rate) || 0;
if (hireRate >= 80) score += 7;
else if (hireRate >= 50) score += 4;

// Penalización: demasiadas propuestas
if (proposals > 35) score -= 10;
if (proposals > 45) score -= 10;

score = Math.max(0, Math.min(100, score));

console.log(`Pre-Score: ${score} | ${d.title || d.full_title} | Props: ${proposals} | Verified: ${d.client_verified}`);

return [{
  json: {
    ...d,
    pre_score: score,
  }
}];
